import React from 'react';
import { FileText, Calendar } from 'lucide-react';

const KnowledgeCard = ({ knowledge, onClick }) => {
  return (
    <div 
      onClick={onClick}
      className="bg-white rounded-lg border border-gray-200 p-5 hover:shadow-lg transition-all duration-300 cursor-pointer group"
    >
      <div className="flex items-start justify-between mb-3">
        <div className="p-2 bg-primary/10 rounded-lg group-hover:bg-primary/20 transition-colors">
          <FileText size={20} className="text-primary" />
        </div>
      </div>
      
      <h3 className="text-lg font-semibold text-gray-900 mb-2">{knowledge.name}</h3>
      <p className="text-gray-600 text-sm line-clamp-2 mb-3">{knowledge.description}</p>
      
      <div className="flex items-center gap-2 text-xs text-gray-400">
        <Calendar size={14} />
        <span>Created On: {knowledge.createdOn}</span>
      </div>
    </div>
  );
};

export default KnowledgeCard;
